# dataset.py
# ─────────────────────────────────────────────────────────────────────────────
# PyTorch Dataset and DataLoader factory for gravitational lens classification.
#
# Expects data/images.npy  (N, H, W) float32
#         data/labels.npy  (N,)      int64
# generated by generate_data.py.
# ─────────────────────────────────────────────────────────────────────────────

import os
import numpy as np
import torch
from torch.utils.data import Dataset, DataLoader
from torchvision import transforms

import config


class LensDataset(Dataset):
    """
    Dataset for gravitational lens binary classification.

    Applies the following preprocessing pipeline per image:
      1. Log-stretch  : log1p(max(x, 0))  — compresses dynamic range
      2. Min-max norm : scale to [0, 1]   — per image
      3. 3-channel    : repeat greyscale across 3 channels
      4. Transform    : augmentation + normalisation (supplied by caller)

    Args:
        images    (np.ndarray): shape (N, H, W), float32 raw simulated images.
        labels    (np.ndarray): shape (N,),      int64  binary labels.
        transform: torchvision transform applied after the preprocessing steps.
    """

    def __init__(self, images: np.ndarray, labels: np.ndarray, transform=None):
        self.images    = images
        self.labels    = labels
        self.transform = transform

    def __len__(self):
        return len(self.labels)

    def __getitem__(self, idx):
        img   = self.images[idx].copy()         # (H, W)
        label = int(self.labels[idx])

        # 1. Log-stretch
        img = np.log1p(np.maximum(img, 0.0))

        # 2. Per-image min-max normalisation → [0, 1]
        lo, hi = img.min(), img.max()
        img    = (img - lo) / (hi - lo + 1e-8)

        # 3. Greyscale → 3-channel tensor  (H, W) → (3, H, W)
        img = torch.from_numpy(img).float().unsqueeze(0).repeat(3, 1, 1)

        # 4. Augmentation / normalisation
        if self.transform is not None:
            img = self.transform(img)

        return img, label


def _build_transforms():
    """Returns (train_transform, val_transform)."""
    train_tf = transforms.Compose([
        transforms.RandomHorizontalFlip(),
        transforms.RandomVerticalFlip(),
        transforms.RandomRotation(degrees=180),   # valid: lenses are isotropic
        transforms.Normalize(config.norm_mean, config.norm_std),
    ])
    val_tf = transforms.Compose([
        transforms.Normalize(config.norm_mean, config.norm_std),
    ])
    return train_tf, val_tf


def get_dataloader(
    images_path : str  = None,
    labels_path : str  = None,
    batch_size  : int  = None,
    val_frac    : float = None,
    test_frac   : float = None,
    seed        : int  = None,
    num_workers : int  = 0,
):
    """
    Build train / val / test DataLoaders from .npy files.

    Defaults are pulled from config.py when arguments are None.

    Returns:
        (train_loader, val_loader, test_loader)
    """
    # Fall back to config defaults
    images_path = images_path or os.path.join(config.data_dir, 'images.npy')
    labels_path = labels_path or os.path.join(config.data_dir, 'labels.npy')
    batch_size  = batch_size  or config.batch_size
    val_frac    = val_frac    if val_frac   is not None else config.val_frac
    test_frac   = test_frac   if test_frac  is not None else config.test_frac
    seed        = seed        if seed       is not None else config.random_seed

    images = np.load(images_path)    # (N, H, W)
    labels = np.load(labels_path)    # (N,)
    N      = len(labels)

    rng  = np.random.default_rng(seed)
    perm = rng.permutation(N)

    n_test  = int(N * test_frac)
    n_val   = int(N * val_frac)
    n_train = N - n_val - n_test

    train_idx = perm[:n_train]
    val_idx   = perm[n_train : n_train + n_val]
    test_idx  = perm[n_train + n_val :]

    train_tf, val_tf = _build_transforms()

    def _make(idx, tf, shuffle):
        ds = LensDataset(images[idx], labels[idx], transform=tf)
        return DataLoader(
            ds, batch_size=batch_size, shuffle=shuffle,
            num_workers=num_workers, pin_memory=torch.cuda.is_available(),
        )

    train_loader = _make(train_idx, train_tf, shuffle=True)
    val_loader   = _make(val_idx,   val_tf,   shuffle=False)
    test_loader  = _make(test_idx,  val_tf,   shuffle=False)

    print(f"[dataset] train={n_train}  val={n_val}  test={n_test}")
    return train_loader, val_loader, test_loader
